import { useNavigate } from "react-router-dom";

export default function Home(){
  const nav = useNavigate();

  return(
    <div style={styles.container}>
      <h1>Daily Worker Platform</h1>

      <div style={styles.cardRow}>

        <div style={styles.card}>
          <h2>Customer</h2>
          <button onClick={()=>nav("/login/customer")}>Login</button>
          <button onClick={()=>nav("/register/customer")}>Register</button>
        </div>

        <div style={styles.card}>
          <h2>Labour</h2>
          <button onClick={()=>nav("/login/labour")}>Login</button>
          <button onClick={()=>nav("/register/labour")}>Register</button>
        </div>

      </div>
    </div>
  )
}

const styles={
  container:{
    textAlign:"center",
    padding:50,
    background:"#f5f7fb",
    height:"100vh"
  },
  cardRow:{
    display:"flex",
    justifyContent:"center",
    gap:20,
    marginTop:40
  },
  card:{
    padding:20,
    border:"1px solid #ddd",
    borderRadius:10,
    background:"white"
  }
}
